args.sparql:
SELECT ?caliphate ?caliph ?position ?rulerLabel ?positionLabel WHERE {
  ?caliphate wdt:P31 wd:Q41787 .
  ?caliphate wdt:P355 ?ruler .
  ?ruler p:P355 ?statement .
  ?statement ps:P355 ?caliphate .
  ?statement pq:P580 ?start .
  FILTER NOT EXISTS {
    ?caliphate wdt:P355 ?other_ruler .
    ?other_ruler p:P355 ?other_statement .
    ?other_statement ps:P355 ?caliphate .
    ?other_statement pq:P580 ?other_start .
    FILTER ( ?other_start < ?start )
  }
  ?ruler p:P39 ?posStatement .
  ?posStatement ps:P39 ?position .
  ?posStatement pq:P582 ?posEnd .
  FILTER ( ?posEnd < ?start )
  OPTIONAL { ?ruler rdfs:label ?rulerLabel . FILTER (LANG(?rulerLabel) = "en") }
  OPTIONAL { ?position rdfs:label ?positionLabel . FILTER (LANG(?positionLabel) = "en") }
}

